15→  import.meta.env.NODE_ENV === 'test' ||
16→  (globalThis as any).__vitest_browser__
17→
18→const apiCache = new Map()
19→
20→const apiGet = async <T>(url: string): Promise<AxiosResponse<T>> => {
21→  // do not cache when testing to avoid flakyness
22→  if (!isMockedEnvironment && apiCache.has(url)) {
23→    return apiCache.get(url)
24→  }
25→
26→  const response = await axios.get<T>(url)
27→
28→  if (!isMockedEnvironment) {
29→    apiCache.set(url, response)
30→  }
31→
32→  return response
33→}
