import { Link } from 'react-router-dom'
import styled, { css } from 'styled-components'

import { Button } from '../../../../components/Button'
import ladies from '../../../../assets/images/ladies.svg'
import { breakpoints } from '../../../../styles/breakpoints'
import { Heading } from '../../../../components/typography'

const Container = styled.div(
  ({ theme: { color } }) => css`
    background: ${color.bannerBackground};
    width: 100%;
    position: relative;
    height: 410px;
    padding-top: 3.75rem;

    @media ${breakpoints.M} {
      padding-top: 6rem;
      height: 566px;
    }
  `
)

const ContentContainer = styled.div`
  text-align: center;
  display: flex;
  align-items: center;
  flex-direction: column;
  z-index: 1;
`

const Image = styled.div<{ src: string }>(
  ({ src }) => css`
    background: url(${src});
    width: 100%;
    height: 100%;
    background-repeat: no-repeat;
    background-position: center bottom;
    background-size: 700px;
    position: absolute;
    bottom: 0;
    @media ${breakpoints.M} {
      background-size: 1000px;
    }
  `
)

const StyledHeading = styled(Heading)(
  ({ theme: { color } }) => `
  margin-bottom: 2.5rem;
  padding: 0 2rem;
  strong {
    color: ${color.primaryText};
    font-weight: 900;
  }
`
)

export const Banner = () => (
  <Container>
    <ContentContainer>
      <StyledHeading level={2}>
        <strong>Hungry?</strong> find your next meal
      </StyledHeading>
      <Link to="/categories">
        <Button>View all restaurants</Button>
      </Link>
    </ContentContainer>
    <Image src={ladies} />
  </Container>
)

import { useMemo } from 'react'

import { ShoppingCartItem } from '../ShoppingCartItem/ShoppingCartItem'
import { CartItem } from '../../../app-state/cart'
import { Body } from '../../typography/Body'
import { toCurrency } from '../../../helpers'

import {
  OrderSummaryContainer,
  BottomContainer,
  CartItemsContainer,
  StyledHeading,
} from './OrderSummary.styles'

type OrderSummaryProps = {
  cartItems: CartItem[]
}

export const OrderSummary = ({ cartItems }: OrderSummaryProps) => {
  const totalPrice = useMemo(
    () => cartItems.map((item) => item.quantity * item.price).reduce((acc, next) => acc + next, 0),
    [cartItems]
  )
  return (
    <>
      <OrderSummaryContainer>
        <StyledHeading level={3} $withMargin>
          Your order
        </StyledHeading>
        <CartItemsContainer>
          {cartItems.length > 0 ? (
            cartItems.map((item) => <ShoppingCartItem key={item.id} item={item} />)
          ) : (
            <Body>Your cart is empty.</Body>
          )}
        </CartItemsContainer>
        <BottomContainer>
          <Body>Total</Body>
          <StyledHeading level={2}>{toCurrency(totalPrice)}</StyledHeading>
        </BottomContainer>
      </OrderSummaryContainer>
    </>
  )
}

